def validate_extension_name(extension_name: str) -> bool:
    """
    Validate that the extension name is safe and allowed.
    - Must match a strict pattern (alphanumeric, underscores, hyphens)
    - Must be in the whitelist of allowed extensions
    """
    if not extension_name:
        return False

    # Strict regex: only lowercase alphanumeric, underscores, and hyphens
    if not re.match(r'^[a-z][a-z0-9_\-]*$', extension_name):
        return False

    # Check against whitelist
    if extension_name not in ALLOWED_EXTENSIONS:
        return False

    return True


def get_db_connection(host: str, port: int, dbname: str, user: str, password: str):
    """Create a secure database connection."""
    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
        sslmode="prefer",
        connect_timeout=10,
    )
    return conn


def list_installed_extensions(conn) -> list:
    """List all currently installed extensions."""
    with conn.cursor() as cur:
        cur.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname;")
        return cur.fetchall()


def list_available_extensions(conn) -> list:
    """List all available extensions that can be installed."""
    with conn.cursor() as cur:
        cur.execute(
            "SELECT name, default_version, comment FROM pg_available_extensions ORDER BY name;"
        )
        return cur.fetchall()


def install_extension(conn, extension_name: str, if_not_exists: bool = True) -> bool:
    """
    Safely install a PostgreSQL extension.

    Uses psycopg2.sql module for safe SQL composition to prevent SQL injection.
    Extension name is validated against a whitelist before execution.
    """
    # Validate extension name against whitelist
    if not validate_extension_name(extension_name):
        print(f"ERROR: Extension '{extension_name}' is not allowed or has an invalid name.")
        print(f"Allowed extensions: {sorted(ALLOWED_EXTENSIONS)}")
        return False

    try:
        # Use psycopg2.sql.Identifier for safe SQL composition
        # This prevents SQL injection by properly quoting the identifier
        if if_not_exists:
            query = psycopg2.sql.SQL("CREATE EXTENSION IF NOT EXISTS {ext}").format(
                ext=psycopg2.sql.Identifier(extension_name)
            )
        else:
            query = psycopg2.sql.SQL("CREATE EXTENSION {ext}").format(
                ext=psycopg2.sql.Identifier(extension_name)
            )

        with conn.cursor() as cur:
            cur.execute(query)
        conn.commit()
        print(f"SUCCESS: Extension '{extension_name}' installed successfully.")
        return True

    except psycopg2.errors.DuplicateObject:
        conn.rollback()
        print(f"INFO: Extension '{extension_name}' is already installed.")
        return True

    except psycopg2.errors.InsufficientPrivilege:
        conn.rollback()
        print(f"ERROR: Insufficient privileges to install extension '{extension_name}'.")
        print("You may need superuser privileges for this extension.")
        return False

    except psycopg2.errors.UndefinedFile:
        conn.rollback()
        print(f"ERROR: Extension '{extension_name}' is not available on this server.")
        print("The extension package may need to be installed on the server OS first.")
        return False

    except psycopg2.Error as e:
        conn.rollback()
        print(f"ERROR: Failed to install extension '{extension_name}': {e}")
        return False


def drop_extension(conn, extension_name: str, if_exists: bool = True, cascade: bool = False) -> bool:
    """
    Safely drop a PostgreSQL extension.
    """
    if not validate_extension_name(extension_name):
        print(f"ERROR: Extension '{extension_name}' is not allowed or has an invalid name.")
        return False

    try:
        if cascade:
            if if_exists:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {ext} CASCADE").format(
                    ext=psycopg2.sql.Identifier(extension_name)
                )
            else:
                query = psycopg2.sql.SQL("DROP EXTENSION {ext} CASCADE").format(
                    ext=psycopg2.sql.Identifier(extension_name)
                )
        else:
            if if_exists:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {ext}").format(
                    ext=psycopg2.sql.Identifier(extension_name)
                )
            else:
                query = psycopg2.sql.SQL("DROP EXTENSION {ext}").format(
                    ext=psycopg2.sql.Identifier(extension_name)
                )

        with conn.cursor() as cur:
            cur.execute(query)
        conn.commit()
        print(f"SUCCESS: Extension '{extension_name}' dropped successfully.")
        return True

    except psycopg2.Error as e:
        conn.rollback()
        print(f"ERROR: Failed to drop extension '{extension_name}': {e}")
        return False


